<script setup lang="ts">import { onBeforeUnmount,onMounted,ref } from 'vue';import { useRoute,useRouter } from 'vue-router';import { useTripStore } from '@/stores/trips';import ViewState from '@/components/ViewState.vue';import StatusBadge from '@/components/StatusBadge.vue';import ConfirmDialog from '@/components/ConfirmDialog.vue';import BudgetSummary from '@/components/trips/BudgetSummary.vue';import ItineraryTimeline from '@/components/trips/ItineraryTimeline.vue';import TripVersionPanel from '@/components/trips/TripVersionPanel.vue';const route=useRoute(),router=useRouter(),store=useTripStore(),id=String(route.params.tripId),dialog=ref<InstanceType<typeof ConfirmDialog>>();onMounted(async()=>{await store.load(id);if(store.current?.status==='READY')await store.loadVersions()});onBeforeUnmount(store.stopPolling);async function remove(){if(await dialog.value?.confirm('确定删除这个行程？此操作会从列表隐藏。')){await store.remove();await router.push('/trips')}}</script>
<template><section class="page"><ViewState :loading="store.loading&&!store.current" :error="store.error" :empty="!store.current" @retry="store.load(id)"><template v-if="store.current"><div class="trip-hero"><div><RouterLink to="/trips" class="back">← 返回行程</RouterLink><p class="eyebrow">{{store.current.startDate}} · {{store.current.days}} DAYS</p><h1 tabindex="-1">{{store.current.destination}}</h1><p>{{store.current.travelers}} 人 · {{store.current.timezone}} <span v-if="store.current.currentVersion">· v{{store.current.currentVersion}}</span></p></div><StatusBadge :status="store.current.status" /></div><div v-if="store.current.status==='GENERATING'" class="generation"><div class="spinner"></div><h2>AI 正在编排行程</h2><p>我们正在平衡时间、预算与偏好，此页面会自动更新。</p></div><div v-else-if="store.current.status==='FAILED'" class="banner error"><h2>生成未完成</h2><p>错误代码：{{store.current.failureCode}}</p></div><template v-else-if="store.current.status==='READY'"><ul v-if="store.current.warnings?.length" class="warnings"><li v-for="warning in store.current.warnings" :key="warning">{{warning}}</li></ul><div class="detail-grid"><ItineraryTimeline :days="store.current.itinerary"/><aside><BudgetSummary :trip="store.current"/><TripVersionPanel/></aside></div></template><button class="danger text-button" @click="remove">删除行程</button><ConfirmDialog ref="dialog"/></template></ViewState></section></template>
